const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
return $input.all().filter(item => {
  return new Date(item.json.timestamp) >= yesterday;
});

const conversations = $input.all();
const total = conversations.length;

let metrics = {
  total_calls: total,
  avg_turns: 0,
  intent_breakdown: {},
  language_breakdown: {},
  emotion_breakdown: {},
  escalation_rate: 0,
  booking_conversion_rate: 0,
  avg_call_duration_turns: 0
};

if (total === 0) return [{ json: metrics }];

let totalTurns = 0;
let escalations = 0;
let bookingIntents = 0;
let bookingsCompleted = 0;

conversations.forEach(c => {
  const data = c.json;
  totalTurns += parseInt(data.turns) || 0;

  // Intent breakdown
  const intent = data.intent || 'unknown';
  metrics.intent_breakdown[intent] = (metrics.intent_breakdown[intent] || 0) + 1;

  // Language breakdown
  const lang = data.language || 'unknown';
  metrics.language_breakdown[lang] = (metrics.language_breakdown[lang] || 0) + 1;

  // Emotion breakdown
  const emotion = data.emotion || 'neutral';
  metrics.emotion_breakdown[emotion] = (metrics.emotion_breakdown[emotion] || 0) + 1;

  if (emotion === 'wants_escalation') escalations++;
  if (intent === 'booking') {
    bookingIntents++;
    // Check if booking was completed by looking at conversation
    try {
      const convo = JSON.parse(data.conversation_json || '[]');
      const lastMsg = convo[convo.length - 1]?.content || '';
      if (lastMsg.includes('confirm') || lastMsg.includes('all set')) {
        bookingsCompleted++;
      }
    } catch (e) {}
  }
});

metrics.avg_turns = Math.round(totalTurns / total);
metrics.escalation_rate = ((escalations / total) * 100).toFixed(1) + '%';
metrics.booking_conversion_rate = bookingIntents > 0
  ? ((bookingsCompleted / bookingIntents) * 100).toFixed(1) + '%'
  : 'N/A';

return [{ json: metrics }];
